// src/pages/CustomerDashboard.jsx

import { useEffect, useState } from "react";

import axios from "axios";

import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const user = JSON.parse(
    localStorage.getItem("user")
  );

  const [requests, setRequests] =
    useState([]);

  const [workers, setWorkers] =
    useState([]);

  const [form, setForm] =
    useState({

      workType: "",

      labourId: "",

      labourName: "",

      location: "",

      date: ""

    });

  const jobs = [

    "Electrician",

    "Plumber",

    "Painter",

    "Carpenter",

    "Cleaner",

    "Technician",

    "Welder",

    "Driver"

  ];

  useEffect(() => {

    getRequests();

  }, []);

  // =========================
  // GET REQUESTS
  // =========================

  const getRequests = async () => {

    try {

      const res = await axios.get(

        `http://localhost:5000/api/request/customer/${user.name}`

      );

      setRequests(res.data);

    } catch (err) {

      console.log(err);

    }
  };

  // =========================
  // SEARCH WORKERS
  // =========================

  const searchWorkers = async (
    work
  ) => {

    try {

      const res = await axios.get(

        "http://localhost:5000/api/auth/workers"

      );

      const filtered =
        res.data.filter((worker) =>

          worker.skills.includes(work)

        );

      setWorkers(filtered);

    } catch (err) {

      console.log(err);

    }
  };

  // =========================
  // SEND REQUEST
  // =========================

  const sendRequest =
    async () => {

      if (

        !form.workType ||

        !form.labourId ||

        !form.location ||

        !form.date

      ) {

        return alert(
          "Please fill all fields"
        );
      }

      try {

        await axios.post(

          "http://localhost:5000/api/request/send",

          {

            customerName:
              user.name,

            customerId:
              user._id,

            labourId:
              form.labourId,

            labourName:
              form.labourName,

            workType:
              form.workType,

            location:
              form.location,

            date:
              form.date,

            timings:
              ["9AM-12PM"]

          }

        );

        alert(
          "Request Sent Successfully"
        );

        setForm({

          workType: "",

          labourId: "",

          labourName: "",

          location: "",

          date: ""

        });

        setWorkers([]);

        getRequests();

      } catch (err) {

        console.log(err);

      }
    };

  // =========================
  // CUSTOMER DECISION
  // =========================

  const customerDecision =
    async (id, decision) => {

      try {

        await axios.put(

          `http://localhost:5000/api/request/customer-decision/${id}`,

          { decision }

        );

        getRequests();

      } catch (err) {

        console.log(err);

      }
    };

  // =========================
  // FEEDBACK
  // =========================

  const submitFeedback =
    async (id) => {

      const rating =
        prompt(
          "Enter Rating (1-5)"
        );

      const comment =
        prompt(
          "Enter Review"
        );

      try {

        await axios.put(

          `http://localhost:5000/api/request/feedback/${id}`,

          {

            rating:
              Number(rating),

            comment

          }

        );

        alert(
          "Feedback Submitted"
        );

        getRequests();

      } catch (err) {

        console.log(err);

      }
    };

  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        {/* LEFT */}

        <div style={styles.leftCard}>

          <h2 style={styles.heading}>
            Hire Workers
          </h2>

          {/* WORK DROPDOWN */}

          <select

            style={styles.input}

            value={form.workType}

            onChange={(e) => {

              setForm({

                ...form,

                workType:
                  e.target.value

              });

              searchWorkers(
                e.target.value
              );
            }}

          >

            <option value="">
              Select Work
            </option>

            {jobs.map(
              (job, index) => (

              <option
                key={index}
                value={job}
              >

                {job}

              </option>

            ))}

          </select>

          {/* WORKERS */}

          {workers.length > 0 && (

            <select

              style={styles.input}

              onChange={(e) => {

                const worker =
                  workers.find(

                    (w) =>
                      w._id ===
                      e.target.value

                  );

                setForm({

                  ...form,

                  labourId:
                    worker._id,

                  labourName:
                    worker.name

                });
              }}

            >

              <option>
                Select Worker
              </option>

              {workers.map(
                (worker) => (

                <option
                  key={worker._id}
                  value={
                    worker._id
                  }
                >

                  {worker.name}
                  {" - "}
                  {worker.city}

                </option>

              ))}

            </select>

          )}

          {/* LOCATION */}

          <input

            style={styles.input}

            placeholder="Enter Location"

            value={form.location}

            onChange={(e) =>
              setForm({

                ...form,

                location:
                  e.target.value

              })
            }

          />

          {/* DATE */}

          <input

            type="date"

            style={styles.input}

            value={form.date}

            onChange={(e) =>
              setForm({

                ...form,

                date:
                  e.target.value

              })
            }

          />

          <button

            style={styles.button}

            onClick={sendRequest}

          >

            Send Request

          </button>

        </div>

        {/* RIGHT */}

        <div style={styles.rightCard}>

          <h2 style={styles.heading}>
            My Requests
          </h2>

          {requests.length === 0 && (

            <p>
              No Requests Found
            </p>

          )}

          {requests.map((req) => (

            <div
              key={req._id}
              style={styles.requestBox}
            >

              <h3>
                {req.labourName}
              </h3>

              <p>
                Work:
                {" "}
                {req.workType}
              </p>

              <p>
                Location:
                {" "}
                {req.location}
              </p>

              <p>
                Date:
                {" "}
                {req.date}
              </p>

              <p>
                Status:
                {" "}
                {req.status}
              </p>

              <p>
                Labour Response:
                {" "}
                {req.labourResponse}
              </p>

              <p>
                Price:
                {" "}
                ₹
                {req.labourPrice}
              </p>

              <p>
                Customer Decision:
                {" "}
                {
                  req.customerDecision
                }
              </p>

              {/* ACCEPT REJECT */}

              {req.labourResponse ===
                "Accepted" &&

                req.customerDecision ===
                  "Waiting" && (

                <div
                  style={
                    styles.btnRow
                  }
                >

                  <button

                    style={
                      styles.acceptBtn
                    }

                    onClick={() =>
                      customerDecision(
                        req._id,
                        "Accepted"
                      )
                    }

                  >

                    Accept

                  </button>

                  <button

                    style={
                      styles.rejectBtn
                    }

                    onClick={() =>
                      customerDecision(
                        req._id,
                        "Rejected"
                      )
                    }

                  >

                    Reject

                  </button>

                </div>

              )}

              {/* FEEDBACK */}

              {req.customerDecision ===
                "Accepted" &&

                !req.feedback && (

                <button

                  style={
                    styles.feedbackBtn
                  }

                  onClick={() =>
                    submitFeedback(
                      req._id
                    )
                  }

                >

                  Give Rating & Review

                </button>

              )}

              {/* SHOW FEEDBACK */}

              {req.feedback && (

                <div
                  style={
                    styles.feedbackBox
                  }
                >

                  <h4>
                    Rating:
                    {" "}
                    {
                      req.feedback
                        .rating
                    }
                    /5
                  </h4>

                  <p>
                    {
                      req.feedback
                        .comment
                    }
                  </p>

                </div>

              )}

            </div>

          ))}

        </div>

      </div>

    </div>
  );
}

const styles = {

  page: {
    background: "#f4f7fb",
    minHeight: "100vh"
  },

  container: {
    display: "grid",
    gridTemplateColumns:
      "1fr 1fr",
    gap: "25px",
    padding: "30px"
  },

  leftCard: {
    background: "white",
    padding: "25px",
    borderRadius: "18px",
    boxShadow:
      "0 4px 15px rgba(0,0,0,0.05)"
  },

  rightCard: {
    background: "white",
    padding: "25px",
    borderRadius: "18px",
    boxShadow:
      "0 4px 15px rgba(0,0,0,0.05)"
  },

  heading: {
    marginBottom: "20px",
    color: "#111827"
  },

  input: {
    width: "100%",
    padding: "14px",
    marginBottom: "16px",
    borderRadius: "10px",
    border:
      "1px solid #d1d5db",
    boxSizing: "border-box"
  },

  button: {
    width: "100%",
    padding: "14px",
    background: "#2563eb",
    color: "white",
    border: "none",
    borderRadius: "10px",
    cursor: "pointer",
    fontSize: "15px"
  },

  requestBox: {
    border:
      "1px solid #e5e7eb",
    borderRadius: "12px",
    padding: "18px",
    marginBottom: "18px"
  },

  btnRow: {
    display: "flex",
    gap: "10px",
    marginTop: "12px"
  },

  acceptBtn: {
    flex: 1,
    padding: "10px",
    background: "green",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer"
  },

  rejectBtn: {
    flex: 1,
    padding: "10px",
    background: "red",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer"
  },

  feedbackBtn: {
